PRAGMA foreign_keys=OFF;

DROP TABLE `quest`;
DROP TABLE `quest_text`;
DROP TABLE `quest_monster`;

CREATE TABLE `quest` (`id` INTEGER NOT NULL, `location_id` INTEGER NOT NULL, `hub_type` TEXT NOT NULL, `stars` INTEGER NOT NULL, `goal_type` TEXT NOT NULL, `quest_type` TEXT NOT NULL, `reward` INTEGER NOT NULL, `fee` INTEGER NOT NULL, `time_limit` INTEGER NOT NULL, PRIMARY KEY(`id`), FOREIGN KEY(`location_id`) REFERENCES `location`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `quest_text` (`quest_id` INTEGER NOT NULL, `language` TEXT NOT NULL, `name` TEXT NOT NULL, `goal` TEXT NOT NULL, `client` TEXT NOT NULL, `description` TEXT NOT NULL, PRIMARY KEY(`quest_id`, `language`), FOREIGN KEY(`quest_id`) REFERENCES `quest`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `quest_monster` (`quest_id` INTEGER NOT NULL, `monster_id` INTEGER NOT NULL, PRIMARY KEY(`quest_id`, `monster_id`), FOREIGN KEY(`quest_id`) REFERENCES `quest`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`monster_id`) REFERENCES `monster`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `quest_reward` (`quest_id` INTEGER NOT NULL, `reward_condition_id` INTEGER NOT NULL, `item_id` INTEGER NOT NULL, `quantity` INTEGER NOT NULL, `percentage` INTEGER NOT NULL, PRIMARY KEY(`quest_id`, `reward_condition_id`, `item_id`, `quantity`), FOREIGN KEY(`quest_id`) REFERENCES `quest`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`reward_condition_id`) REFERENCES `reward_condition`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`item_id`) REFERENCES `item`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `quest_supply` (`quest_id` INTEGER NOT NULL, `item_id` INTEGER NOT NULL, `quantity` INTEGER NOT NULL, `box_order` INTEGER NOT NULL, PRIMARY KEY(`quest_id`, `item_id`, `box_order`), FOREIGN KEY(`quest_id`) REFERENCES `quest`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`item_id`) REFERENCES `item`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );

